('news-003', 'Riset Terapan Informatika untuk Solusi Digital Masyarakat', 'riset-terapan-informatika-solusi-digital', 'Penelitian', '2026-08-24T00:00:00.000Z', 'Berita placeholder tentang arah penelitian terapan yang berfokus pada kebutuhan akademik, organisasi, dan masyarakat.', 'Isi berita riset ini masih berupa data dummy dan tidak memuat klaim atau nama pihak tertentu.', NULL, 'published', 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('news-004', 'Inisiasi Kerja Sama Pembelajaran dan Literasi Teknologi', 'inisiasi-kerja-sama-literasi-teknologi', 'Kerja Sama', '2026-09-02T00:00:00.000Z', 'Informasi dummy tentang peluang kolaborasi untuk mendukung kegiatan akademik, pelatihan, dan pengembangan kompetensi.', 'Konten kerja sama ini disiapkan agar struktur CMS dapat diuji tanpa memakai nama mitra resmi.', NULL, 'published', 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('news-005', 'Pengumuman Layanan Administrasi Akademik Semester Berjalan', 'pengumuman-layanan-administrasi-akademik', 'Pengumuman', '2026-09-08T00:00:00.000Z', 'Pengumuman placeholder mengenai layanan akademik, jadwal koordinasi, dan informasi umum yang dapat diperbarui.', 'Isi pengumuman ini merupakan contoh untuk kebutuhan pengujian halaman daftar dan detail berita.', NULL, 'draft', 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('news-006', 'Dokumentasi Kegiatan Pengabdian Berbasis Literasi Digital', 'dokumentasi-pengabdian-literasi-digital', 'Kemahasiswaan', '2026-09-15T00:00:00.000Z', 'Berita dummy mengenai kegiatan pengabdian yang melibatkan mahasiswa dalam edukasi teknologi secara bertanggung jawab.', 'Konten pengabdian ini masih placeholder dan dapat diperluas menjadi berita lengkap setelah data resmi tersedia.', NULL, 'published', 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);

